local Monster = {}

local function init()
    local config = FileUtil.getConfigFromCsv("setting/MonsterConfig.csv")
    for _, item in pairs(config) do
        local data = {}
        data.type = tonumber(item.Type) or 1
        data.actor = tostring(item.Actor) or "boy.actor"
        data.frameTime = tonumber(item.FrameTime) or 1000
        data.maxNum = tonumber(item.MaxNum) or 10
        data.hp = tonumber(item.Hp) or 10
        data.lifeTime = tonumber(item.LifeTime) or 10
        data.patrolSpeed = tonumber(item.PatrolSpeed) or 1
        data.patrolInterval = tonumber(item.PatrolInterval) or 1
        data.patrolRadius = tonumber(item.PatrolRadius) or 1
        data.followSpeed = tonumber(item.FollowSpeed) or 1
        data.followRadius = tonumber(item.FollowRadius) or 1
        data.attack = tonumber(item.Attack) or 1
        data.attackRadius = tonumber(item.AttackRadius) or 1
        data.attackInterval = tonumber(item.AttackInterval) or 1
        data.repel = tonumber(item.Repel) or 0
        data.knock = tonumber(item.Knock) or 0
        data.Repelled = tonumber(item.Repelled) or 0.5
        Monster[data.type] = data
    end
end

init()

MonsterConfig = {}

function MonsterConfig:getConfigByType(type)
    return Monster[tonumber(type)]
end

